import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

const CATEGORIES = ['Technology', 'Arts', 'Sports', 'Academic', 'Cultural', 'Business', 'Science', 'Social', 'Other'];

const EMPTY_FORM = {
  title: '', description: '', category: 'Technology', startDate: '', endDate: '',
  venue: '', isVirtual: false, virtualLink: '', maxParticipants: '',
  allowExternal: false, tags: '', coverImage: '',
};

export default function CommunityAdminEvents() {
  const [events, setEvents] = useState([]);
  const [community, setCommunity] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingEvent, setEditingEvent] = useState(null);
  const [form, setForm] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [participants, setParticipants] = useState([]);
  const [statusFilter, setStatusFilter] = useState('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const [evRes, comRes] = await Promise.all([
        api.get('/events/my-community'),
        api.get('/communities/my/profile'),
      ]);
      setEvents(evRes.data.data || []);
      setCommunity(comRes.data.data);
    } catch { toast.error('Failed to load events'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const openCreate = () => { setEditingEvent(null); setForm(EMPTY_FORM); setShowModal(true); };
  const openEdit = (ev) => {
    setEditingEvent(ev);
    setForm({
      title: ev.title, description: ev.description, category: ev.category,
      startDate: ev.startDate?.split('T')[0], endDate: ev.endDate?.split('T')[0] || '',
      venue: ev.venue || '', isVirtual: ev.isVirtual, virtualLink: ev.virtualLink || '',
      maxParticipants: ev.maxParticipants || '', allowExternal: ev.allowExternal,
      tags: ev.tags?.join(', ') || '', coverImage: ev.coverImage || '',
    });
    setShowModal(true);
  };

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        tags: form.tags ? form.tags.split(',').map(t => t.trim()).filter(Boolean) : [],
        maxParticipants: form.maxParticipants ? parseInt(form.maxParticipants) : undefined,
      };
      if (editingEvent) {
        await api.put(`/events/${editingEvent._id}`, payload);
        toast.success('Event updated!');
      } else {
        await api.post('/events', payload);
        toast.success('Event created!');
      }
      setShowModal(false);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save event');
    } finally {
      setSaving(false);
    }
  };

  const updateStatus = async (id, status) => {
    try {
      await api.put(`/events/${id}/status`, { status });
      toast.success(`Event ${status}!`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update status');
    }
  };

  const deleteEvent = async (id, title) => {
    if (!window.confirm(`Delete "${title}"?`)) return;
    try {
      await api.delete(`/events/${id}`);
      toast.success('Event deleted');
      fetchData();
    } catch { toast.error('Failed'); }
  };

  const viewParticipants = async (ev) => {
    setSelectedEvent(ev);
    try {
      const res = await api.get(`/events/${ev._id}/participants`);
      setParticipants(res.data.data || []);
    } catch { setParticipants([]); }
  };

  const filteredEvents = statusFilter ? events.filter(e => e.status === statusFilter) : events;

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>EVENT <span className="gradient-text">MANAGEMENT</span></h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>{community?.name}</p>
            </div>
            <div style={{ display: 'flex', gap: 10 }}>
              <Link to="/community-admin" className="btn btn-outline">← Dashboard</Link>
              <button onClick={openCreate} className="btn btn-primary">+ New Event</button>
            </div>
          </div>
        </div>

        {/* Status filter */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          {[['', 'All'], ['draft', 'Draft'], ['published', 'Published'], ['completed', 'Completed'], ['cancelled', 'Cancelled']].map(([v, l]) => (
            <button key={v} onClick={() => setStatusFilter(v)} className={`btn btn-sm ${statusFilter === v ? 'btn-primary' : 'btn-outline'}`}>{l}</button>
          ))}
        </div>

        {filteredEvents.length === 0 ? (
          <div className="empty-state">
            <div className="empty-state-icon">📅</div>
            <div>No events found</div>
            <button onClick={openCreate} className="btn btn-primary btn-sm" style={{ marginTop: 14 }}>Create First Event</button>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            {filteredEvents.map(ev => (
              <div key={ev._id} className="card">
                <div style={{ display: 'flex', alignItems: 'flex-start', gap: 16, flexWrap: 'wrap' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8, flexWrap: 'wrap' }}>
                      <h4 style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem' }}>{ev.title}</h4>
                      <span className={`badge badge-${ev.status}`}>{ev.status}</span>
                      <span className={`badge badge-${ev.category?.toLowerCase()}`}>{ev.category}</span>
                      {ev.allowExternal && ev.eventCode && (
                        <span style={{ background: 'rgba(16,185,129,0.15)', color: 'var(--success)', border: '1px solid rgba(16,185,129,0.3)', borderRadius: 100, padding: '3px 10px', fontSize: '0.7rem', fontFamily: 'var(--font-mono)' }}>
                          CODE: {ev.eventCode}
                        </span>
                      )}
                    </div>
                    <p style={{ fontSize: '0.825rem', color: 'var(--text-secondary)', marginBottom: 10 }}>
                      {ev.description?.substring(0, 120)}...
                    </p>
                    <div style={{ display: 'flex', gap: 20, fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                      <span>📅 {new Date(ev.startDate).toLocaleDateString()}</span>
                      {ev.venue && <span>📍 {ev.venue}</span>}
                      {ev.isVirtual && <span>💻 Virtual</span>}
                      <span>👥 {ev.participants?.length || 0} registered</span>
                    </div>
                  </div>

                  {/* Actions */}
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 8, alignItems: 'flex-end' }}>
                    {/* Status transitions */}
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                      {ev.status === 'draft' && (
                        <button onClick={() => updateStatus(ev._id, 'published')} className="btn btn-sm" style={{ background: 'rgba(59,130,246,0.2)', border: '1px solid var(--blue-accent)', color: 'var(--blue-accent)' }}>
                          Publish
                        </button>
                      )}
                      {ev.status === 'published' && (
                        <>
                          <button onClick={() => updateStatus(ev._id, 'completed')} className="btn btn-success btn-sm">Complete</button>
                          <button onClick={() => updateStatus(ev._id, 'draft')} className="btn btn-outline btn-sm">Unpublish</button>
                        </>
                      )}
                      {ev.status === 'cancelled' && (
                        <button onClick={() => updateStatus(ev._id, 'draft')} className="btn btn-outline btn-sm">Restore to Draft</button>
                      )}
                      {(ev.status === 'draft' || ev.status === 'published') && (
                        <button onClick={() => updateStatus(ev._id, 'cancelled')} className="btn btn-danger btn-sm">Cancel</button>
                      )}
                    </div>
                    <div style={{ display: 'flex', gap: 6 }}>
                      <button onClick={() => viewParticipants(ev)} className="btn btn-outline btn-sm">👥 Participants</button>
                      <button onClick={() => openEdit(ev)} className="btn btn-outline btn-sm">✏️ Edit</button>
                      <button onClick={() => deleteEvent(ev._id, ev.title)} className="btn btn-sm" style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)', color: 'var(--danger)' }}>🗑</button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Event Form Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowModal(false)}>
          <div className="modal" style={{ maxWidth: 640 }}>
            <h3 className="modal-title">{editingEvent ? 'EDIT EVENT' : 'CREATE EVENT'}</h3>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginBottom: 24 }}>
              {editingEvent ? 'Update event details' : 'New event starts as a Draft'}
            </p>

            <form onSubmit={handleSave}>
              <div className="form-group">
                <label className="form-label">Title *</label>
                <input className="form-control" value={form.title} onChange={e => set('title', e.target.value)} placeholder="Event title" required />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group">
                  <label className="form-label">Category</label>
                  <select className="form-control" value={form.category} onChange={e => set('category', e.target.value)}>
                    {CATEGORIES.map(c => <option key={c}>{c}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Start Date *</label>
                  <input className="form-control" type="date" value={form.startDate} onChange={e => set('startDate', e.target.value)} required />
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Description *</label>
                <textarea className="form-control" rows={3} value={form.description} onChange={e => set('description', e.target.value)} placeholder="Describe the event..." required style={{ resize: 'vertical' }} />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group">
                  <label className="form-label">Venue</label>
                  <input className="form-control" value={form.venue} onChange={e => set('venue', e.target.value)} placeholder="Physical location" />
                </div>
                <div className="form-group">
                  <label className="form-label">Max Participants</label>
                  <input className="form-control" type="number" value={form.maxParticipants} onChange={e => set('maxParticipants', e.target.value)} placeholder="Unlimited if empty" />
                </div>
              </div>

              <div style={{ display: 'flex', gap: 24, marginBottom: 16 }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  <input type="checkbox" checked={form.isVirtual} onChange={e => set('isVirtual', e.target.checked)} />
                  Virtual Event
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  <input type="checkbox" checked={form.allowExternal} onChange={e => set('allowExternal', e.target.checked)} />
                  Allow External Participants (generates join code)
                </label>
              </div>

              {form.isVirtual && (
                <div className="form-group">
                  <label className="form-label">Virtual Link</label>
                  <input className="form-control" value={form.virtualLink} onChange={e => set('virtualLink', e.target.value)} placeholder="https://meet.google.com/..." />
                </div>
              )}

              <div className="form-group">
                <label className="form-label">Tags (comma-separated)</label>
                <input className="form-control" value={form.tags} onChange={e => set('tags', e.target.value)} placeholder="tech, workshop, networking" />
              </div>

              <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', marginTop: 8 }}>
                <button type="button" onClick={() => setShowModal(false)} className="btn btn-outline">Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>
                  {saving ? 'Saving...' : editingEvent ? 'Update Event' : 'Create Event'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Participants Modal */}
      {selectedEvent && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setSelectedEvent(null)}>
          <div className="modal">
            <div className="flex-between" style={{ marginBottom: 20 }}>
              <h3 className="modal-title">PARTICIPANTS</h3>
              <button onClick={() => setSelectedEvent(null)} style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '1.2rem' }}>✕</button>
            </div>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: 16 }}>{selectedEvent.title} — {participants.length} registered</p>

            {participants.length === 0 ? (
              <div className="empty-state"><div>No participants yet</div></div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {participants.map((p, i) => (
                  <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 14px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)' }}>
                    <div className="avatar" style={{ width: 28, height: 28, fontSize: '0.7rem' }}>
                      {(p.user?.name || p.externalName)?.charAt(0)}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: '0.85rem', fontWeight: 600 }}>{p.user?.name || p.externalName}</div>
                      <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>{p.user?.email || p.externalEmail}</div>
                    </div>
                    <span className={`badge badge-${p.type}`}>{p.type}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
